package com.example.payment.handler;

import java.util.Date;
import java.util.Map;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.Executors;
import java.util.concurrent.ScheduledExecutorService;
import java.util.concurrent.TimeUnit;

/**
 * A simple in-memory validator for WS-Security Timestamps to prevent replay attacks.
 * In a real-world scenario, this would be backed by a persistent store (database, distributed cache).
 */
public class TimestampValidator {

    private static final long MAX_AGE_MS = 5 * 60 * 1000; // Timestamps older than 5 minutes are invalid
    private static final long CLOCK_SKEW_TOLERANCE_MS = 5 * 1000; // 5 seconds clock skew tolerance
    private static final long CLEANUP_INTERVAL_MS = 60 * 1000; // Clean up every 1 minute

    private static TimestampValidator instance;

    // Stores processed timestamp IDs with their expiration time for replay protection
    private final Map<String, TimestampInfo> processedTimestamps;
    private final ScheduledExecutorService scheduler;

    private TimestampValidator() {
        processedTimestamps = new ConcurrentHashMap<>();
        scheduler = Executors.newSingleThreadScheduledExecutor();
        scheduler.scheduleAtFixedRate(this::cleanUpExpiredTimestamps, CLEANUP_INTERVAL_MS, CLEANUP_INTERVAL_MS, TimeUnit.MILLISECONDS);
        System.out.println("TimestampValidator initialized. Cleanup scheduled.");
    }

    public static synchronized TimestampValidator getInstance() {
        if (instance == null) {
            instance = new TimestampValidator();
        }
        return instance;
    }

    /**
     * Validates a WS-Security timestamp for freshness and uniqueness.
     *
     * @param id The wsu:Id attribute of the Timestamp.
     * @param created The wsu:Created timestamp.
     * @param expires The wsu:Expires timestamp.
     * @return true if the timestamp is valid and not replayed, false otherwise.
     */
    public boolean isValid(String id, Date created, Date expires) {
        long currentTime = System.currentTimeMillis();

        // 1. Check for immediate replay (has this exact ID been processed recently?)
        if (processedTimestamps.containsKey(id)) {
            System.err.println("Replay detected for timestamp ID: " + id);
            return false;
        }

        // 2. Check if the timestamp is too old (Created time is too far in the past)
        if (created.getTime() < (currentTime - MAX_AGE_MS - CLOCK_SKEW_TOLERANCE_MS)) {
            System.err.println("Timestamp too old. Created: " + created + ", Current: " + new Date(currentTime) + ", ID: " + id);
            return false;
        }

        // 3. Check if the timestamp is in the future (due to large clock skew or malicious intent)
        // Allow a small clock skew. Created should not be significantly after current time.
        if (created.getTime() > (currentTime + CLOCK_SKEW_TOLERANCE_MS)) {
            System.err.println("Timestamp Created in the future (large clock skew). Created: " + created + ", Current: " + new Date(currentTime) + ", ID: " + id);
            return false;
        }

        // 4. Check if the timestamp has already expired
        if (expires.getTime() < currentTime - CLOCK_SKEW_TOLERANCE_MS) {
            System.err.println("Timestamp expired. Expires: " + expires + ", Current: " + new Date(currentTime) + ", ID: " + id);
            return false;
        }

        // 5. Check if the expiration is too far in the future (optional, depends on policy)
        // If expires is excessively far, it might indicate an issue. For this example, we just check against Created's max age.
        if (expires.getTime() > (created.getTime() + MAX_AGE_MS + CLOCK_SKEW_TOLERANCE_MS)) {
            System.err.println("Timestamp Expires too far in the future relative to Created. ID: " + id);
            // This is a policy decision. Could reject or just log. For strong replay protection, expiration should be bounded.
        }

        // If all checks pass, mark the timestamp as processed.
        processedTimestamps.put(id, new TimestampInfo(id, created, expires));
        System.out.println("Timestamp ID " + id + " validated and added to processed list.");
        return true;
    }

    // Periodically remove timestamps that have definitely expired and are unlikely to be replayed.
    private void cleanUpExpiredTimestamps() {
        long currentTime = System.currentTimeMillis();
        int initialSize = processedTimestamps.size();
        processedTimestamps.entrySet().removeIf(entry -> entry.getValue().getExpires().getTime() < (currentTime - MAX_AGE_MS)); // Remove if expires + MAX_AGE_MS has passed
        int cleanedSize = initialSize - processedTimestamps.size();
        if (cleanedSize > 0) {
            System.out.println("Cleaned up " + cleanedSize + " expired timestamps. Current size: " + processedTimestamps.size());
        }
    }

    // Helper class to store timestamp details
    private static class TimestampInfo {
        private final String id;
        private final Date created;
        private final Date expires;

        public TimestampInfo(String id, Date created, Date expires) {
            this.id = id;
            this.created = created;
            this.expires = expires;
        }

        public String getId() {
            return id;
        }

        public Date getCreated() {
            return created;
        }

        public Date getExpires() {
            return expires;
        }
    }

    public void shutdown() {
        scheduler.shutdown();
        try {
            if (!scheduler.awaitTermination(5, TimeUnit.SECONDS)) {
                scheduler.shutdownNow();
            }
        } catch (InterruptedException e) {
            scheduler.shutdownNow();
            Thread.currentThread().interrupt();
        }
        System.out.println("TimestampValidator shut down.");
    }
}
