package com.example.payment.handler;

import org.w3c.dom.Element;
import org.w3c.dom.NodeList;

import javax.xml.datatype.DatatypeFactory;
import javax.xml.datatype.XMLGregorianCalendar;
import javax.xml.namespace.QName;
import javax.xml.soap.*;
import javax.xml.ws.handler.MessageContext;
import javax.xml.ws.handler.soap.SOAPHandler;
import javax.xml.ws.handler.soap.SOAPMessageContext;
import javax.xml.ws.soap.SOAPFaultException;
import java.util.Date;
import java.util.Set;

public class SecurityHeaderHandler implements SOAPHandler<SOAPMessageContext> {

    // WS-Security Namespaces
    public static final String WSSE_NS = "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-secext-1.0.xsd";
    public static final String WSU_NS = "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-utility-1.0.xsd";
    public static final String WSSE_PREFIX = "wsse";
    public static final String WSU_PREFIX = "wsu";

    @Override
    public Set<QName> getHeaders() {
        // We are interested in the WS-Security header
        return Set.of(new QName(WSSE_NS, "Security", WSSE_PREFIX));
    }

    @Override
    public boolean handleMessage(SOAPMessageContext context) {
        Boolean outboundProperty = (Boolean) context.get(MessageContext.MESSAGE_OUTBOUND_PROPERTY);

        // Process inbound messages only
        if (!outboundProperty) {
            try {
                SOAPMessage soapMessage = context.getMessage();
                SOAPHeader soapHeader = soapMessage.getSOAPHeader();

                if (soapHeader == null) {
                    throw createSOAPFaultException("Missing SOAP header.", "Client.Security");
                }

                // Find wsse:Security header
                NodeList securityElements = soapHeader.getElementsByTagNameNS(WSSE_NS, "Security");
                if (securityElements.getLength() == 0) {
                    System.err.println("SOAP message missing WS-Security header.");
                    throw createSOAPFaultException("Missing WS-Security header.", "Client.Security");
                }
                Element securityHeader = (Element) securityElements.item(0);

                // Find wsu:Timestamp inside wsse:Security header
                NodeList timestampElements = securityHeader.getElementsByTagNameNS(WSU_NS, "Timestamp");
                if (timestampElements.getLength() == 0) {
                    System.err.println("WS-Security header missing wsu:Timestamp.");
                    throw createSOAPFaultException("Missing WS-Security Timestamp.", "Client.Security");
                }
                Element timestampElement = (Element) timestampElements.item(0);

                // Extract wsu:Id, wsu:Created, and wsu:Expires
                String timestampId = timestampElement.getAttributeNS(WSU_NS, "Id");
                if (timestampId == null || timestampId.isEmpty()) {
                    System.err.println("Timestamp missing wsu:Id attribute.");
                    throw createSOAPFaultException("Missing wsu:Id attribute on Timestamp.", "Client.Security");
                }

                String createdStr = getChildElementText(timestampElement, WSU_NS, "Created");
                String expiresStr = getChildElementText(timestampElement, WSU_NS, "Expires");

                if (createdStr == null || expiresStr == null) {
                    System.err.println("Timestamp missing Created or Expires element. Created: " + createdStr + ", Expires: " + expiresStr);
                    throw createSOAPFaultException("Timestamp missing Created or Expires element.", "Client.Security");
                }

                DatatypeFactory df = DatatypeFactory.newInstance();
                XMLGregorianCalendar createdXmlCal = df.newXMLGregorianCalendar(createdStr);
                XMLGregorianCalendar expiresXmlCal = df.newXMLGregorianCalendar(expiresStr);

                Date created = createdXmlCal.toGregorianCalendar().getTime();
                Date expires = expiresXmlCal.toGregorianCalendar().getTime();

                // Validate timestamp for replay protection
                if (!TimestampValidator.getInstance().isValid(timestampId, created, expires)) {
                    System.err.println("Validation failed for timestamp ID: " + timestampId);
                    throw createSOAPFaultException("Invalid or replayed timestamp.", "Client.Security.InvalidTimestamp");
                }

                System.out.println("WS-Security Timestamp validated successfully. ID: " + timestampId);

                // Optionally, store timestamp details in the message context for the service implementation to access
                context.put("ws-security.timestamp.id", timestampId);
                context.put("ws-security.timestamp.created", created);
                context.put("ws-security.timestamp.expires", expires);
                context.setScope("ws-security.timestamp.id", MessageContext.Scope.APPLICATION);
                context.setScope("ws-security.timestamp.created", MessageContext.Scope.APPLICATION);
                context.setScope("ws-security.timestamp.expires", MessageContext.Scope.APPLICATION);

            } catch (SOAPFaultException e) {
                System.err.println("SOAP Fault during security processing: " + e.getFault().getFaultCodeAsQName().getLocalPart() + " - " + e.getMessage());
                throw e; // Re-throw the SOAPFaultException
            } catch (Exception e) {
                System.err.println("Unexpected error during WS-Security processing: " + e.getMessage());
                e.printStackTrace();
                throw createSOAPFaultException("Internal server error during security processing: " + e.getMessage(), "Server.InternalError");
            }
        }
        return true; // Continue processing the message
    }

    @Override
    public boolean handleFault(SOAPMessageContext context) {
        // Log the fault, potentially do cleanup or custom fault handling
        System.err.println("SecurityHeaderHandler: handleFault called.");
        return true;
    }

    @Override
    public void close(MessageContext context) {
        // Resources cleanup if necessary
    }

    private SOAPFaultException createSOAPFaultException(String reason, String faultCode) {
        try {
            SOAPFactory soapFactory = SOAPFactory.newInstance();
            SOAPFault fault = soapFactory.createFault();
            fault.setFaultString(reason);
            // Use SOAP 1.1 fault codes as specified in WS-Security for general faults.
            // Example: Client for sender-side errors, Server for receiver-side errors.
            fault.setFaultCode(new QName(SOAPConstants.URI_NS_SOAP_1_1_ENVELOPE, faultCode, "env"));
            return new SOAPFaultException(fault);
        } catch (SOAPException e) {
            System.err.println("Failed to create SOAPFault: " + e.getMessage());
            throw new RuntimeException("Failed to create SOAPFault", e);
        }
    }

    private String getChildElementText(Element parentElement, String namespace, String localName) {
        NodeList children = parentElement.getElementsByTagNameNS(namespace, localName);
        if (children.getLength() > 0) {
            return children.item(0).getTextContent();
        }
        return null;
    }
}
