package com.example.payment.service;

import com.example.payment.data.PaymentRequest;
import com.example.payment.data.PaymentResponse;

import javax.annotation.Resource;
import javax.jws.HandlerChain;
import javax.jws.WebService;
import javax.xml.ws.WebServiceContext;
import javax.xml.ws.handler.MessageContext;
import java.util.Date;
import java.util.UUID;

@WebService(endpointInterface = "com.example.payment.service.PaymentService",
            serviceName = "PaymentGatewayService",
            portName = "PaymentGatewayServicePort",
            targetNamespace = "http://service.payment.example.com/")
@HandlerChain(file = "/handler-chain.xml")
public class PaymentServiceImpl implements PaymentService {

    @Resource
    private WebServiceContext wsContext;

    @Override
    public PaymentResponse processPayment(PaymentRequest paymentRequest) {
        System.out.println("Received Payment Request:");
        System.out.println("  Transaction ID: " + paymentRequest.getTransactionId());
        System.out.println("  Account Number: " + paymentRequest.getAccountNumber()); // In real app, don't log full sensitive data
        System.out.println("  Amount: " + paymentRequest.getAmount() + " " + paymentRequest.getCurrency());
        System.out.println("  Description: " + paymentRequest.getDescription());

        // Access timestamp details put by the SecurityHeaderHandler (for logging/auditing)
        MessageContext msgContext = wsContext.getMessageContext();
        String timestampId = (String) msgContext.get("ws-security.timestamp.id");
        Date timestampCreated = (Date) msgContext.get("ws-security.timestamp.created");
        Date timestampExpires = (Date) msgContext.get("ws-security.timestamp.expires");

        if (timestampId != null) {
            System.out.println("  WS-Security Timestamp ID: " + timestampId);
            System.out.println("  Timestamp Created: " + timestampCreated);
            System.out.println("  Timestamp Expires: " + timestampExpires);
        }

        // Simulate payment processing logic
        String authorizationCode = UUID.randomUUID().toString().substring(0, 8).toUpperCase();
        boolean success = true;
        String message = "Payment processed successfully.";

        if (paymentRequest.getAmount() <= 0) {
            success = false;
            message = "Payment amount must be positive.";
            authorizationCode = null;
        } else if (paymentRequest.getAccountNumber() == null || paymentRequest.getAccountNumber().isEmpty()) {
            success = false;
            message = "Account number cannot be empty.";
            authorizationCode = null;
        }
        // Add more complex business rules here

        System.out.println("Payment Processing Result: " + (success ? "SUCCESS" : "FAILED") +
                           " for Transaction ID: " + paymentRequest.getTransactionId());

        return new PaymentResponse(paymentRequest.getTransactionId(), success, message, authorizationCode);
    }
}
