package com.example.payment;

import com.example.payment.handler.TimestampValidator;
import com.example.payment.service.PaymentServiceImpl;

import javax.xml.ws.Endpoint;

public class Publisher {

    public static void main(String[] args) {
        String address = "http://localhost:8080/paymentGateway";
        System.out.println("Starting Payment Gateway SOAP service at " + address);

        // Ensure TimestampValidator is initialized and its cleanup task is running
        TimestampValidator.getInstance();

        Endpoint.publish(address, new PaymentServiceImpl());

        System.out.println("Payment Gateway SOAP service is published.");
        System.out.println("WSDL available at " + address + "?wsdl");
        System.out.println("Press Ctrl+C to stop the service.");

        // Add a shutdown hook to gracefully stop the TimestampValidator's cleanup thread
        Runtime.getRuntime().addShutdownHook(new Thread(() -> {
            System.out.println("Shutting down Payment Gateway service...");
            TimestampValidator.getInstance().shutdown();
            System.out.println("Service stopped.");
        }));
    }
}